diff --git a/absl/numeric/int128.h b/absl/numeric/int128.h
index 32603b0..921e514 100644
+++ b/absl/numeric/int128.h
+namespace literals {
+namespace uint128_internal {
+
+template <uint128 Accumulator, char... Chars>
+struct ParseUint128;
+
+template <uint128 Acc>
+struct ParseUint128<Acc> {
+  static constexpr uint128 value = Acc;
+};
+
+template <uint128 Acc, char C, char... Rest>
+struct ParseUint128<Acc, C, Rest...> {
+  static constexpr uint128 value =
+      ParseUint128<Acc * uint128(10) + uint128(C - '0'), Rest...>::value;
+};
+
+}  // namespace uint128_internal
+
+template <char... Chars>
+constexpr uint128 operator"" _u128() {
+  return uint128_internal::ParseUint128<uint128(0), Chars...>::value;
+}
+
+}  // namespace literals
